var url = "https://edu-icam25-duval1.odoo.com";
var db = "edu-icam25-duval1";
var username = "constyl.fotso@2026.icam.fr";
var password = "Dembaba@10.";

msg.url = url + "/jsonrpc";
msg.headers = { "Content-Type": "application/json" };

msg.payload = {
    "jsonrpc": "2.0",
    "method": "call",
    "params": {
        "service": "common",
        "method": "login",
        "args": [db, username, password]
    },
    "id": 1
};

msg.odoo_config = { db: db, password: password, url: url };
return msg;

if (msg.payload.result) {
    var uid = msg.payload.result;
    global.set("odoo_uid", uid);
    global.set("odoo_db", msg.odoo_config.db);
    global.set("odoo_password", msg.odoo_config.password);
    global.set("odoo_url", msg.odoo_config.url);
    node.status({fill:"green", shape:"dot", text:"Connecté UID: "+uid});
} else {
    node.status({fill:"red", shape:"ring", text:"Erreur Auth"});
}
return msg;

var topicParts = msg.topic.split('/');
var posteStr = topicParts[1]; 
var tag = msg.payload.tag;

msg.target_poste = (posteStr === 'poste1') ? 1 : 2;
msg.tag_rfid = tag;

if (posteStr === 'poste1') {
    flow.set("last_tag_p1", tag);
    return [msg, null]; 
} else if (posteStr === 'poste2') {
    var expectedTag = flow.get("last_tag_p1");
    if (tag === expectedTag) {
        return [msg, null];
    } else {
        var errorMsg = {
            payload: {
                type: "ERREUR_SEQUENCE",
                poste: 2, 
                message: "Mauvais chariot ! Attendu: " + (expectedTag || "Inconnu")
            }
        };
        return [null, errorMsg];
    }
}
return null;

var uid = global.get("odoo_uid");
var db = global.get("odoo_db");
var password = global.get("odoo_password");
var url = global.get("odoo_url");

if (!uid) return null;

// 1. Logique d'état adaptative
var allowed_states = ["confirmed", "progress"];
if (msg.target_poste === 2) {
    // Le Poste 1 a déjà validé l'OF, il est donc probablement "done" ou "to_close"
    allowed_states = ["confirmed", "progress", "done", "to_close"];
}

msg.url = url + "/jsonrpc";
msg.payload = {
    jsonrpc: "2.0",
    method: "call",
    params: {
        service: "object",
        method: "execute_kw",
        args: [
            db, uid, password,
            "mrp.production",
            "search_read",
            [[["x_rfid_tag", "=", msg.tag_rfid], ["state", "in", allowed_states]]],
            { 
                fields: ["id", "name", "product_id", "qty_producing", "state"], 
                limit: 1, 
                order: "id desc" // CRUCIAL : Prendre le plus récent si plusieurs OF ont le même tag
            }
        ]
    },
    id: 2
};
return msg;

var res = msg.payload.result;
if (!res || res.length === 0) return null;

var ofData = res[0];
var productName = ofData.product_id[1];

if (msg.target_poste === 1) flow.set("current_of_id_p1", ofData.id);
if (msg.target_poste === 2) flow.set("current_of_id_p2", ofData.id);

const variants = {
    "Chariot 1": { p1: ["Barquette Oui", "Cadre Oui", "Supports Pied Fixe"], p2: ["Roue Grise (x2)", "Roue Rouge (x2)"] }
    // ... (autres chariots idems)
};

var config = variants[productName] || variants["Chariot 1"];
var specificSteps = (msg.target_poste === 1) ? config.p1 : config.p2;

msg.payload = {
    type: "NOUVEAU_CHARIOT",
    poste: msg.target_poste,
    tag: msg.tag_rfid,
    instructions: {
        of: ofData.name,
        variante: productName,
        etapes: specificSteps,
        temps_alloue: 15
    }
};
return msg;

var data = JSON.parse(msg.payload);
if (data.type !== "VALIDATION") return null;

var uid = global.get("odoo_uid");
var db = global.get("odoo_db");
var password = global.get("odoo_password");
var url = global.get("odoo_url");

// On récupère l'ID Odoo mis en mémoire lors du scan
var ofId = (data.poste === 1) ? flow.get("current_of_id_p1") : flow.get("current_of_id_p2");

if (!uid || !ofId) return null;

msg.poste_source = data.poste;
msg.url = url + "/jsonrpc";
msg.payload = {
    jsonrpc: "2.0",
    method: "call",
    params: {
        service: "object",
        method: "execute_kw",
        args: [db, uid, password, "mrp.production", "write", [[ofId], {"qty_producing": 1}]]
    },
    id: 5
};
return msg;

// Si l'update Odoo est OK, on demande à Flutter de vider l'écran
if (msg.payload.result) {
    var clearMsg = {
        payload: {
            type: "CHANGEMENT_POSTE",
            poste_source: msg.poste_source
        }
    };

    // On vide aussi les IDs en mémoire flow
    if (msg.poste_source === 1) flow.set("current_of_id_p1", null);
    if (msg.poste_source === 2) flow.set("current_of_id_p2", null);

    // Mise à jour du Dashboard de supervision
    var dashboardMsg = {
        payload: "En attente...",
        color: "#6c757d" // Gris
    };
    if (msg.poste_source === 1) {
        node.send([null, dashboardMsg, null]); // Sortie 2 pour le UI
    } else if (msg.poste_source === 2) {
        node.send([null, null, dashboardMsg]); // Sortie 3 pour le UI
    }

    return clearMsg;
}
return null;

var ofId = flow.get("current_of_id_p1");
if (!ofId) return null;

var uid = global.get("odoo_uid");
var db = global.get("odoo_db");
var password = global.get("odoo_password");
var url = global.get("odoo_url");

msg.poste_source = 1;
msg.url = url + "/jsonrpc";
msg.payload = {
    jsonrpc: "2.0",
    method: "call",
    params: {
        service: "object",
        method: "execute_kw",
        args: [db, uid, password, "mrp.production", "write", [[ofId], {"qty_producing": 1}]]
    },
    id: 5
};
return msg;

msg.payload = {
    type: "ALERTE_ANDON",
    poste: 2,
    message: "Alerte physique activée au Poste 2 !"
};
return msg;

msg.payload = "Actif - Chariot ID: " + msg.payload.tag;
msg.color = "#28a745"; // Vert
return msg;

msg.payload = "Actif - Chariot ID: " + msg.payload.tag;
msg.color = "#28a745"; 
return msg;

msg.payload = "ALERTE PRODUCTION ! (Intervention requise au Poste 2)";
msg.color = "white";
msg.background = "red";
return msg;

msg.color = "black";
msg.background = "#e2e3e5"; // Gris clair
return msg;
